function timingSafeEqual(a, b) {
  const bufA = Buffer.from(String(a));
  const bufB = Buffer.from(String(b));
  if (bufA.length !== bufB.length) {
    // Compare against itself to maintain constant time, then return false
    crypto.timingSafeEqual(bufA, bufA);
    return false;
  }
  return crypto.timingSafeEqual(bufA, bufB);
}

function issueAuthorizationCode(res, clientId, redirectUri, userId, state, scope, codeChallenge, codeChallengeMethod) {
  const code = generateSecureToken(32);

  authorizationCodes.set(code, {
    clientId,
    redirectUri,
    userId,
    scope: scope || '',
    codeChallenge: codeChallenge || null,
    codeChallengeMethod: codeChallengeMethod || null,
    expiresAt: Date.now() + 60000, // 1 minute expiry (short-lived)
    used: false
  });

  const redirectUrl = new URL(redirectUri);
  redirectUrl.searchParams.set('code', code);
  redirectUrl.searchParams.set('state', state);

  res.redirect(302, redirectUrl.toString());
}

function redirectWithError(res, redirectUri, error, description, state) {
  const redirectUrl = new URL(redirectUri);
  redirectUrl.searchParams.set('error', error);
  redirectUrl.searchParams.set('error_description', description);
  if (state) redirectUrl.searchParams.set('state', state);
  res.redirect(302, redirectUrl.toString());
}

