app.post('/token', tokenRateLimit, (req, res) => {
  const { grant_type } = req.body;

  if (grant_type === 'authorization_code') {
    return handleAuthorizationCodeGrant(req, res);
  } else if (grant_type === 'refresh_token') {
    return handleRefreshTokenGrant(req, res);
  } else {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Only authorization_code and refresh_token grant types are supported.'
    });
  }
});

function authenticateClient(req) {
  // Support both Basic auth and body parameters
  const authHeader = req.headers.authorization;
  let clientId, clientSecret;

  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const colonIndex = decoded.indexOf(':');
    if (colonIndex === -1) return null;
    clientId = decodeURIComponent(decoded.slice(0, colonIndex));
    clientSecret = decodeURIComponent(decoded.slice(colonIndex + 1));
  } else {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  if (!clientId || !registeredClients[clientId]) return null;

  const client = registeredClients[clientId];

  // If client_secret is provided, validate it
  if (clientSecret) {
    if (!timingSafeEqual(client.client_secret, clientSecret)) return null;
  }

  return { clientId, client, secretProvided: !!clientSecret };
}

function handleAuthorizationCodeGrant(req, res) {
  const { code, redirect_uri, code_verifier } = req.body;

  // Authenticate client
  const auth = authenticateClient(req);
  if (!auth) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed.'
    });
  }

  const { clientId, secretProvided } = auth;

  // Validate authorization code
  if (!code || !authorizationCodes.has(code)) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid authorization code.'
    });
  }

  const codeData = authorizationCodes.get(code);

  // Check if code was already used (prevent replay attacks)
  if (codeData.used) {
    // Code reuse detected - revoke all tokens issued with this code
    authorizationCodes.delete(code);
    // In production, also revoke associated tokens
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has already been used. Possible replay attack detected.'
    });
  }

  // Mark code as used immediately
  codeData.used = true;

  // Check expiration
  if (codeData.expiresAt < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has expired.'
    });
  }

  // Validate client_id matches
  if (codeData.clientId !== clientId) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was not issued to this client.'
    });
  }

  // Validate redirect_uri matches exactly
  if (codeData.redirectUri !== redirect_uri) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'redirect_uri does not match the one used in the authorization request.'
    });
  }

  // PKCE validation
  if (codeData.codeChallenge) {
    if (!code_verifier) {
      authorizationCodes.delete(code);
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'code_verifier is required.'
      });
    }

    const method = codeData.codeChallengeMethod || 'plain';
    const expectedChallenge = generateCodeVerifierChallenge(code_verifier, method);

    if (!timingSafeEqual(expectedChallenge, codeData.codeChallenge)) {
      authorizationCodes.delete(code);
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'Invalid code_verifier.'
      });
    }
  } else if (!secretProvided) {
    // If no PKCE and no client secret, reject (public clients must use PKCE)
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Public clients must use PKCE.'
    });
  }

  // Delete the authorization code (single use)
  authorizationCodes.delete(code);

  // Generate tokens
  const accessToken = generateSecureToken(32);
  const refreshToken = generateSecureToken(32);

  accessTokens.set(accessToken, {
    clientId,
    userId: codeData.userId,
    scope: codeData.scope,
    expiresAt: Date.now() + 3600000 // 1 hour
  });

  refreshTokens.set(refreshToken, {
    clientId,
    userId: codeData.userId,
    scope: codeData.scope
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: refreshToken,
    scope: codeData.scope
  });
}

function handleRefreshTokenGrant(req, res) {
  const { refresh_token } = req.body;

  // Authenticate client
  const auth = authenticateClient(req);
  if (!auth) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed.'
    });
  }

  const { clientId } = auth;

  if (!refresh_token || !refreshTokens.has(refresh_token)) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid refresh token.'
    });
  }

  const tokenData = refreshTokens.get(refresh_token);

  // Validate client_id matches
  if (tokenData.clientId !== clientId) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token was not issued to this client.'
    });
  }

  // Rotate refresh token (invalidate old one, issue new one)
  refreshTokens.delete(refresh_token);

  const newAccessToken = generateSecureToken(32);
  const newRefreshToken = generateSecureToken(32);

  accessTokens.set(newAccessToken, {
    clientId,
    userId: tokenData.userId,
    scope: tokenData.scope,
    expiresAt: Date.now() + 3600000
  });

  refreshTokens.set(newRefreshToken, {
    clientId,
    userId: tokenData.userId,
    scope: tokenData.scope
  });

  res.json({
    access_token: newAccessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: newRefreshToken,
    scope: tokenData.scope
  });
}

// --- Token Revocation Endpoint ---

app.post('/revoke', (req, res) => {
  const { token, token_type_hint } = req.body;

  const auth = authenticateClient(req);
  if (!auth) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed.'
    });
  }

  if (!token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Token parameter is required.'
    });
  }

  // Try to revoke as access token
  if (token_type_hint !== 'refresh_token' && accessTokens.has(token)) {
    const tokenData = accessTokens.get(token);
    if (tokenData.clientId === auth.clientId) {
      accessTokens.delete(token);
    }
  }

  // Try to revoke as refresh token
  if (token_type_hint !== 'access_token' && refreshTokens.has(token)) {
    const tokenData = refreshTokens.get(token);
    if (tokenData.clientId === auth.clientId) {
      refreshTokens.delete(token);
    }
  }

  // Always return 200 per RFC 7009
  res.status(200).json({});
});

// --- Token Introspection Endpoint ---

app.post('/introspect', (req, res) => {
  const auth = authenticateClient(req);
  if (!auth) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed.'
    });
  }

  const { token } = req.body;

  if (!token) {
    return res.json({ active: false });
  }

  if (accessTokens.has(token)) {
    const tokenData = accessTokens.get(token);
    if (tokenData.expiresAt > Date.now()) {
      return res.json({
        active: true,
        client_id: tokenData.clientId,
        username: tokenData.userId,
        scope: tokenData.scope,
        exp: Math.floor(tokenData.expiresAt / 1000),
        token_type: 'Bearer'
      });
    }
  }

  res.json({ active: false });
});

// --- UserInfo Endpoint ---

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Missing or invalid Bearer token.' });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData || tokenData.expiresAt < Date.now()) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token is invalid or expired.' });
  }

  const user = users[tokenData.userId];
  if (!user) {
    return res.status(404).json({ error: 'user_not_found' });
  }

  res.json({
    sub: tokenData.userId,
    name: user.name,
    email: user.email
  });
});

// --- Logout Endpoint ---

app.post('/logout', (req, res) => {
  const sessionId = parseCookies(req)['session_id'];
  if (sessionId) {
    sessions.delete(sessionId);
  }
  res.setHeader('Set-Cookie', 'session_id=; HttpOnly; Secure; SameSite=Strict; Path=/; Max-Age=0');
  res.json({ message: 'Logged out successfully.' });
});

